#!/usr/bin/env node
/**
 * Reapply vendored scratch-* patches after `npm install`.
 *
 * The vendored scratch-vm and scratch-render are tracked outside the main
 * dependency tree (see vendored/ in .gitignore). We carry a couple of
 * targeted source patches against vendored/scaffolding/node_modules/scratch-render
 * (see patches/scratch-render+0.1.0.patch) that we reapply here so the
 * `vendored/scaffolding/dist/scaffolding-min.js` UMD never needs to be
 * regenerated by hand after a fresh checkout.
 *
 * Behavior:
 *  - If vendored/scaffolding/node_modules/scratch-render is not installed
 *    yet (e.g. user has not run `cd vendored/scaffolding && npm install`),
 *    this script exits 0 with a hint. Re-run it once vendored deps are in
 *    place.
 *  - patch-package is invoked from vendored/scaffolding so its package
 *    resolution works against that local node_modules tree.
 *  - The patches/ directory lives at the project root so it stays under
 *    version control (vendored/ is gitignored).
 *
 * Exit code is always 0 on purpose — this script is wired into
 * `postinstall`, which must not break `npm install` for unrelated reasons.
 */

import { spawnSync } from 'node:child_process';
import { existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const root = resolve(here, '..');
const patchesDir = resolve(root, 'patches');
const scaffoldingDir = resolve(root, 'vendored', 'scaffolding');
const renderPkg = resolve(scaffoldingDir, 'node_modules', 'scratch-render', 'package.json');

if (!existsSync(renderPkg)) {
  console.warn(
    '[apply-vendored-patches] vendored/scaffolding/node_modules/scratch-render not installed; skipping.\n' +
      '                Run `cd vendored/scaffolding && npm install`, then re-run `npm run apply:scratch-render-patch`.',
  );
  process.exit(0);
}

// patch-package resolves --patch-dir relative to the app root it discovers
// (vendored/scaffolding), so we pass the relative path from there.
const relativePatchesDir = '../../patches';

const result = spawnSync(
  process.execPath,
  [resolve(root, 'node_modules', 'patch-package', 'index.js'), '--patch-dir', relativePatchesDir],
  {
    cwd: scaffoldingDir,
    stdio: 'inherit',
    shell: false,
  },
);

if (result.status !== 0) {
  console.error(
    '[apply-vendored-patches] patch-package exited with code ' +
      result.status +
      '. The patches/ directory is unchanged; resolve the conflict and try again.',
  );
  process.exit(0);
}
